import numpy as np
import sys, os, csv
sys.path.insert(0, '.')
from scipy.integrate import odeint
from scipy.optimize import least_squares

path = '/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited/'

def minmax(v):
    mn, mx = v.min(), v.max()
    if mx - mn <= 0: return np.zeros_like(v)
    return (v - mn) / (mx - mn)

def parse_param(h):
    import re
    m = re.search(r'(\d+(?:\.\d+)?)\s*uM', h, re.I)
    if m: return float(m.group(1))
    m = re.search(r'(\d+(?:\.\d+)?)\s*mM', h, re.I)
    if m: return float(m.group(1)) * 1000
    m = re.search(r'(\d+(?:\.\d+)?)\s*ng/ul', h, re.I)
    if m: return float(m.group(1))
    m = re.search(r'pH\s+(\d+(?:\.\d+)?)', h, re.I)
    if m: return float(m.group(1))
    m = re.search(r'(\d+(?:\.\d+)?)\s*%', h)
    if m: return float(m.group(1))
    return None

def load_dataset(fpath):
    with open(fpath) as f:
        reader = csv.reader(f, delimiter='\t')
        header = next(reader)
        rows = [r for r in reader if r]
    params_raw = [parse_param(h) for h in header[1:]]
    if all(p is not None for p in params_raw):
        params = [float(p) for p in params_raw]
    else:
        params = [float(i+1) for i in range(len(header)-1)]
    feats, tgts = [], []
    for row in rows:
        t = float(row[0])
        for param, val in zip(params, row[1:]):
            if val and val.strip().lower() != 'nan':
                feats.append([t, param])
                tgts.append(float(val))
    X = np.array(feats); y = np.array(tgts)
    X_norm = np.column_stack([minmax(X[:,i]) for i in range(X.shape[1])])
    y_norm = minmax(y)
    return np.column_stack([X_norm, y_norm]), y_norm

def fit_and_score(fpath):
    try:
        X, y = load_dataset(fpath)
        # Current ODE: dc/dt = (c0 + c1*x2)*(1 + c2*x1)*(1-x2)
        def rhs(x2v, tv, param, c0, c1, c2):
            return (c0 + c1*x2v) * (1 + c2*param) * (1 - x2v)

        def residual(theta):
            c0, c1, c2 = theta
            preds = []
            for param in np.unique(X[:,1]):
                idx = np.flatnonzero(X[:,1]==param)
                ord_idx = idx[np.argsort(X[idx,0])]
                ts = X[ord_idx, 0]
                y0 = y[ord_idx[0]]
                try:
                    sol = odeint(rhs, y0, ts, args=(param, c0, c1, c2)).ravel()
                    preds.extend(zip(ord_idx, sol))
                except: return np.full(len(y), 1e6)
            pred = np.zeros(len(y))
            for i, v in preds: pred[i] = v
            return pred - y

        best = None; best_loss = np.inf
        for init in [[0.1, 10., 2.], [0.3, 5., 1.], [0.01, 30., 0.]]:
            try:
                fit = least_squares(residual, init, loss='soft_l1', max_nfev=200)
                loss = np.mean(fit.fun**2)
                if loss < best_loss: best_loss = loss; best = fit
            except: pass
        if best is None: return np.inf
        var = np.var(y)
        nmse = best_loss / var if var > 0 else best_loss
        return nmse
    except Exception as e:
        return np.inf

datasets = []
for dirpath, _, filenames in os.walk(path):
    if 'fit.tsv' in filenames:
        rel = os.path.relpath(dirpath, path)
        datasets.append((rel, os.path.join(dirpath, 'fit.tsv')))
datasets.sort()

results = []
for name, fpath in datasets:
    nmse = fit_and_score(fpath)
    results.append((name, nmse))

results.sort(key=lambda x: x[1], reverse=True)
print('Top 8 hardest datasets:')
for name, nmse in results[:8]:
    print(f'  {nmse:.4f}  {name}')
print(f'Mean NMSE: {np.mean([r[1] for r in results if np.isfinite(r[1])]):.4f}')
